.data-table td.numeric {
  font-feature-settings: "tnum"; /* Activates tabular figures */
  font-variant-numeric: tabular-nums; /* Modern equivalent/shorthand */
}

/* For older browsers or specific needs, you might use: */
.legacy-numeric {
  -webkit-font-feature-settings: "tnum";
  -moz-font-feature-settings: "tnum";
  font-feature-settings: "tnum";
}
